func TestListParticipantsAggregatesDirections(t *testing.T) {
	s, err := Open(filepath.Join(t.TempDir(), "data.db"))
	if err != nil {
		t.Fatalf("open: %v", err)
	}
	defer s.Close()
	now := time.Now().UnixMilli()
	if _, err := s.UpsertGmailMessages(context.Background(), []StoredMessage{
		{ID: "m1", ThreadID: "t1", AccountEmail: "user@example.com", From: "user@example.com", To: "alice@example.com", Subject: "Sent", InternalDate: now},
		{ID: "m2", ThreadID: "t1", AccountEmail: "user@example.com", From: "alice@example.com", To: "user@example.com", Subject: "Reply", InternalDate: now + 1},
		{ID: "m3", ThreadID: "t2", AccountEmail: "user@example.com", From: "bob@example.com", To: "user@example.com", Subject: "Received", InternalDate: now + 2},
	}); err != nil {
		t.Fatalf("upsert: %v", err)
	}
	participants, err := s.ListParticipants(context.Background(), ParticipantFilter{AccountEmail: "user@example.com", Since: time.Now().Add(-time.Hour)})
	if err != nil {
		t.Fatalf("ListParticipants: %v", err)
	}
	if len(participants) != 2 {
		t.Fatalf("participants = %+v want 2", participants)
	}
	alice := participants[1]
	if participants[0].Email == "alice@example.com" {
		alice = participants[0]
	}
	if alice.Count != 2 || alice.Direction != "both" || len(alice.Threads) != 1 {
		t.Fatalf("alice summary wrong: %+v", alice)
	}
}

func TestShowParticipantMissingReturnsEmptySummary(t *testing.T) {
	s, err := Open(filepath.Join(t.TempDir(), "data.db"))
	if err != nil {
		t.Fatalf("open: %v", err)
	}
	defer s.Close()
	summary, err := s.ShowParticipant(context.Background(), "missing@example.com", ParticipantFilter{AccountEmail: "user@example.com"})
	if err != nil {
		t.Fatalf("ShowParticipant: %v", err)
	}
	if summary.Email != "missing@example.com" || summary.Direction != "none" {
		t.Fatalf("summary = %+v", summary)
	}
}
